-- ============================================================
-- ABPN DIPLOMATE / BOARD CERTIFICATION AUDITOR
-- The person who verifies a psychiatrist's or neurologist's
-- credentials are real, current, and legitimately obtained.
-- ============================================================

INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES (
  'citizen-abpn-001',
  'ABPN Diplomate Credential Verification Specialist',
  'Healthcare Credentialing Compliance',
  'Healthcare',
  'ABPN Diplomate Credential Verification Specialist — verifies board certification status, MOC compliance, and credential legitimacy for psychiatrists and neurologists',
  'ABPN Diplomate Credential Verification Specialist',
  'American Board of Psychiatry and Neurology (ABPN); ABMS (American Board of Medical Specialties); National Practitioner Data Bank (NPDB); State Medical Boards',
  'ABPN Bylaws and Policies (certification, MOC, disciplinary actions); ABMS Standards for Initial Certification and Continuing Certification; 42 USC 11101-11152 (Health Care Quality Improvement Act — NPDB reporting); 42 CFR Part 60 (NPDB regulations); 45 CFR 60.12 (reporting requirements); California Bus. & Prof. Code Sections 2000-2529 (Medical Practice Act — licensure verification); CMS Conditions of Participation 42 CFR 482.12(a)(7) (medical staff credentialing); CMS Conditions of Participation 42 CFR 482.22 (medical staff composition); TJC MS.06.01.01-MS.06.01.05 (credentialing and privileging); ABPN subspecialty certifications: Addiction Psychiatry, Child and Adolescent Psychiatry, Forensic Psychiatry, Geriatric Psychiatry, Pain Medicine, Brain Injury Medicine, Neurodevelopmental Disabilities',
  'ABPN Certification Verification Service standards; ABMS Board Certification Report; NPDB Continuous Query enrollment standards; National Committee for Quality Assurance (NCQA) credentialing standards (CR-1 through CR-8); URAC Health Plan credentialing standards; CVO (Credentials Verification Organization) accreditation standards; AMA Physician Masterfile verification; Federation of State Medical Boards (FSMB) DocInfo verification; Joint Commission Medical Staff Standards; CAQH ProView standards for provider data; primary source verification methodology (direct confirmation from issuing body)',
  'SOC 2 Type II (Processing Integrity, Confidentiality, Security); primary source verification documentation for each credential element (medical school, residency, fellowship, board certification, state licensure, DEA registration); ABPN certification status verification (active, expired, revoked, voluntary surrender); MOC (Maintenance of Certification) compliance tracking — ABPN requires ongoing participation including Part 1 (Professional Standing), Part 2 (Lifelong Learning), Part 3 (Assessment of Knowledge), Part 4 (Improvement in Medical Practice); NPDB query documentation (initial and biennial); adverse action reporting verification (malpractice payments, licensure actions, clinical privilege restrictions, DEA actions); hospital privilege verification for each facility; malpractice insurance verification; OIG/GSA exclusion list screening (monthly LEIE check); state medical board disciplinary action search; time-limited credential expiration tracking and re-verification; peer reference verification; competency assessment documentation; AMA profile discrepancy investigation; gap analysis for unexplained practice interruptions',
  'Board certification certificate; MOC status report; NPDB Self-Query Response; NPDB Continuous Query notification; State medical license verification; DEA registration certificate; Medical school diploma verification; Residency completion verification; Fellowship completion verification; Hospital privilege delineation; Malpractice claims history; FSMB Board Action Databank report; AMA Physician Masterfile report; CAQH ProView attestation; OIG exclusion screening results; Peer reference letters; Competency evaluation; CME completion records; Professional liability insurance face sheet'
);

-- ============================================================
-- COMPETENCY EVALUATOR (PC 1367-1376)
-- The person who evaluates whether a defendant is competent
-- to stand trial. Critical — this is a gatekeeper function.
-- ============================================================

INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES (
  'citizen-comp-eval-001',
  'Competency to Stand Trial Evaluator (PC 1367)',
  'Forensic Mental Health Compliance',
  'Legal Courts',
  'Competency to Stand Trial Evaluator — conducts court-ordered evaluations under PC 1367-1376 to determine if defendant understands proceedings and can assist counsel',
  'Competency to Stand Trial Evaluator (PC 1367)',
  'California Superior Court; Department of State Hospitals (DSH); Board of Psychology; Medical Board of California; ABPN (Forensic Psychiatry subspecialty)',
  'California Penal Code Sections 1367-1376 (competency proceedings); PC 1367 (standard: unable to understand nature of proceedings or assist counsel in rational manner); PC 1368 (doubt of competency — duty to declare); PC 1369 (trial on competency — expert testimony, right to jury); PC 1370 (commitment to DSH if found incompetent — maximum commitment periods); PC 1370.01 (misdemeanor competency — different commitment rules); PC 1370.1 (developmentally disabled defendants — Regional Center evaluation); PC 1372 (certificate of restoration — DSH Medical Director certification); PC 1375 (civil commitment after maximum commitment); Dusky v. United States 362 US 402 (1960) (federal competency standard: sufficient present ability to consult with lawyer with reasonable degree of rational understanding AND rational as well as factual understanding of proceedings); Drope v. Missouri 420 US 162 (1975) (duty to inquire sua sponte); People v. Rodas (2018) 6 Cal.5th 219 (California competency standard); California Rules of Court Rule 4.130 (proceedings regarding mental competence); Evidence Code Section 730 (court-appointed expert); Evidence Code Section 1017 (psychotherapist-patient privilege exception for court-ordered evaluation)',
  'American Academy of Psychiatry and the Law (AAPL) Practice Guidelines for Forensic Psychiatric Evaluation of Defendants Raising the Insanity Defense and for Forensic Assessment of Competency to Stand Trial; APA (American Psychological Association) Specialty Guidelines for Forensic Psychology; ABFP (American Board of Forensic Psychology) certification standards; ABPN subspecialty certification in Forensic Psychiatry; California Board of Psychology forensic evaluation standards; DSH Competency Evaluation guidelines; standardized competency assessment instruments: MacArthur Competence Assessment Tool — Criminal Adjudication (MacCAT-CA), Competency Screening Test (CST), Georgia Court Competency Test (GCCT), Evaluation of Competency to Stand Trial — Revised (ECST-R), Competency to Stand Trial Assessment Instrument (CAI); Judicial Council Form CR-111 (Order for Examination); forensic report writing standards per AAPL Ethics Guidelines',
  'SOC 2 Type II (Processing Integrity, Confidentiality); court order verification before conducting evaluation; Miranda-type advisement to defendant (limits of confidentiality, non-treatment purpose, report will be disclosed to court and counsel); evaluation methodology documentation (instruments used, clinical interview, collateral information reviewed, records reviewed); opinion basis documentation linking clinical findings to Dusky/PC 1367 legal standard; prior competency evaluation review; medication status documentation (capacity to participate may be affected by psychotropic medication — Sell v. United States 539 US 166); malingering assessment documentation (SIRS-2, TOMM, other symptom validity testing); report submission timeliness (court-ordered deadline compliance); DSH admission coordination documentation (if committed); restoration treatment documentation; certificate of restoration review; re-evaluation documentation if competency re-raised; privilege and confidentiality management (evaluation is NOT treatment — no psychotherapist-patient privilege per EC 1017); chain of custody for evaluation notes and records',
  'Court Order for Competency Evaluation (CR-111); Competency Evaluation Report; Competency Assessment Instrument scoring records; Clinical interview notes; Collateral information log; Records reviewed inventory; Malingering assessment results; Certificate of Incompetence (if found IST); DSH Admission Order; Restoration Treatment Plan; Progress Reports to Court; Certificate of Restoration of Competency; Medication capacity evaluation (Sell analysis); Re-evaluation report; Expert testimony preparation materials'
);

-- ============================================================
-- POST COMPLIANCE OFFICER / POST TRAINING AUDITOR
-- Audits whether peace officers have completed required POST
-- training, certification is current, and departments are
-- in compliance with POST standards.
-- ============================================================

INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES (
  'citizen-post-001',
  'POST Compliance Auditor / Peace Officer Training Standards Specialist',
  'Law Enforcement Training Compliance',
  'Gov Le Digital',
  'POST Compliance Auditor — verifies peace officer training compliance, POST certification status, and department adherence to POST standards',
  'POST Compliance Auditor / Peace Officer Training Standards Specialist',
  'California Commission on Peace Officer Standards and Training (POST); California Department of Justice; State Legislature (via Penal Code)',
  'California Penal Code Sections 13500-13553 (POST enabling statutes); PC 13510 (POST authority to set minimum standards); PC 13510.1 (continuing professional training requirement — 24 hours every 2 years minimum); PC 13515 (elder/dependent adult abuse training); PC 13515.25 (racial profiling — racial and identity profiling training); PC 13515.27 (implicit bias and cultural diversity training); PC 13515.28 (use of force — de-escalation training); PC 13515.29 (mental health crisis intervention training); PC 13516 (domestic violence training); PC 13516.5 (human trafficking training); PC 13517 (sexual assault investigation training); PC 13519 (racial profiling training); PC 13519.4 (hate crimes training); PC 13519.8 (persons with developmental disabilities training); PC 13523 (missing persons training); PC 13525 (elder abuse training for investigators); PC 13540-13542 (fraudulent POST certificates — criminal penalties); Government Code Section 1029-1031.5 (minimum peace officer standards — citizenship, age, fingerprinting, background, psych screening, medical exam); Government Code Section 1031(f) (moral character); 11 CCR Sections 1000-1099 (POST Regulations — training requirements, certification, standards); AB 846 (2020) (disqualification for officers with prior misconduct); SB 2 (2021) (Peace Officer Decertification Act — POST authority to revoke certification); SB 960 (2022) (DACA recipients eligible for peace officer); POST Administrative Manual; POST Regulations Procedure D-1 (Basic Course requirements — 664+ hours minimum)',
  'POST Basic Course curriculum standards (Regular Basic Course — 42 Learning Domains, 664+ hours); POST Field Training Program standards (POST Guidelines, minimum 10 weeks); POST Supervisory Course requirements; POST Management Course; POST Executive Development Course; POST Continuing Professional Training (CPT) guidelines — 24 hours minimum biennially with mandated subjects; POST Perishable Skills Program (PSP) — annual qualification in arrest/control, driver awareness/simulation, tactical firearms; POST Basic Course Waiver standards for lateral transfers; POST Academy instructor certification standards; POST course certification requirements (presentation, testing, and evaluation); POST Regular Basic Course testing standards (comprehensive final, scenario testing); California POST Learning Portal standards; POST Compliance Review methodology; Department Training Manager (DTM) standards and certification',
  'SOC 2 Type II (Processing Integrity, Security, Confidentiality); POST Profile database verification (individual officer training records); Basic Course completion certificate verification; POST certificate issuance tracking (Basic, Intermediate, Advanced, Supervisory, Management, Executive); CPT compliance monitoring — biennial 24-hour requirement with documentation of specific mandated courses completed; Perishable Skills completion tracking (annual firearms qualification records, arrest/control certification, driver training); field training program completion verification (Daily Observation Reports, weekly evaluations, final evaluation); background investigation file completeness audit per Government Code 1031 (personal history statement, polygraph/CVSA, psychological screening report, medical examination, criminal history check, reference checks, prior employer contacts); SB 2 decertification compliance — reporting serious misconduct to POST; National Decertification Index (NDI) query documentation; Brady list / Pitchess motion disclosure tracking; personnel complaint investigation documentation; body-worn camera policy compliance; use of force reporting and review documentation; Early Warning System / Early Intervention System data tracking; department POST compliance audit documentation; Training Records Management System integrity; POST reimbursement audit trail',
  'POST Basic Certificate; POST Intermediate Certificate; POST Advanced Certificate; POST Supervisory Certificate; POST Management Certificate; POST Executive Certificate; Basic Course completion certificate; CPT completion records; Perishable Skills annual qualification records; Field Training Officer (FTO) certification; Daily Observation Reports (DORs); Background investigation file; Personal History Statement (POST PHS-2); Psychological screening report; Medical examination clearance; Polygraph/CVSA results; Department training plan; POST compliance audit report; SB 2 misconduct report; Brady/Pitchess disclosure index; Use of force reports; Body-worn camera policy; Early Warning System alerts; Firearms qualification records; Arrest and control certification; Department POST profile report'
);

