INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES (
  'citizen-opd-oversight-001',
  'Oakland Police Department Compliance Auditor (NSA/Federal Oversight)',
  'Law Enforcement Oversight Compliance',
  'Gov Le Digital',
  'OPD Compliance Auditor — monitors compliance with Negotiated Settlement Agreement, federal court orders, and court-appointed monitor requirements',
  'Oakland Police Department Compliance Auditor (NSA/Federal Oversight)',
  'U.S. District Court, Northern District of California; Court-Appointed Compliance Director/Monitor; Oakland Police Commission; Community Police Review Agency (CPRA); Oakland City Council',
  'Delphine Allen et al. v. City of Oakland (Case No. C00-4599 TEH) — Negotiated Settlement Agreement (NSA) (2003); 42 USC 14141 (now 34 USC 12601) (Pattern or Practice of Police Misconduct); NSA Tasks 1-52 (specific reform requirements); Oakland City Charter Section 604(b)(5) (Police Commission authority); Oakland Municipal Code Chapter 2.45 (Community Police Review Agency); Oakland Measure LL (2016, Police Commission establishment); Oakland Measure S1 (2020, Police Commission expansion); California Government Code Section 3300-3313 (Peace Officers Bill of Rights — POBR); California Penal Code Section 832.7 (personnel records disclosure — SB 1421, SB 16); Penal Code Section 13012 (use of force reporting to DOJ); AB 748 (body camera footage release); SB 1421 (officer misconduct records disclosure); SB 16 (expanded disclosure of sustained findings)',
  'NSA compliance assessment methodology (court-appointed monitor framework); OPD Policy and Procedure Manual standards; NACOLE (National Association for Civilian Oversight of Law Enforcement) standards; DOJ Collaborative Reform Initiative methodology; Police Executive Research Forum (PERF) use of force guidelines; IACP (International Association of Chiefs of Police) model policies; Oakland Police Commission policy review standards; Stanford Criminal Justice Center Monitoring Report methodology; CPRA investigation standards',
  'SOC 2 Type II (Processing Integrity, Security, Confidentiality); NSA task compliance tracking (52 tasks — each with specific measurable requirements); court-appointed monitor quarterly report verification; use of force review documentation (Type I through Type IV classification); Internal Affairs Division investigation timeliness tracking (180-day POBR statute of limitations); complaint classification and disposition tracking; officer discipline audit; early intervention system (Risk Management Dashboard) alert documentation; body-worn camera activation compliance audit; stop data collection per RIPA (AB 953); pursuit policy compliance; training completion verification; community engagement documentation; Police Commission policy recommendation tracking; CPRA investigation outcome tracking; federal court status conference compliance; sustained complaint disclosure per SB 1421/SB 16',
  'Negotiated Settlement Agreement compliance report; Court-appointed monitor quarterly report; NSA task completion documentation; Use of force reports (all types); Internal Affairs investigation files; Citizen complaint files; Early intervention system alerts; Body-worn camera footage audit log; RIPA stop data reports; Pursuit reports; Training compliance records; Police Commission meeting minutes; CPRA investigation reports; Federal court status conference transcripts; Community policing activity reports; Officer discipline records; Brady/Pitchess index; Annual report to court'
);

